from flask import Flask, request, Response
from prometheus_client import generate_latest, Counter, Gauge, Histogram, REGISTRY
from prometheus_client.core import CollectorRegistry
import time
import random

app = Flask(__name__)

# ----------------------------------------------------------------------------------------------------------------------
# Prometheus Metrics
# ----------------------------------------------------------------------------------------------------------------------

# Counter for total requests
REQUESTS_TOTAL = Counter(
    'http_requests_total',
    'Total number of HTTP requests.',
    ['method', 'endpoint', 'status_code']
)

# Histogram for request duration (latency)
REQUEST_DURATION_SECONDS = Histogram(
    'http_request_duration_seconds',
    'HTTP request duration in seconds.',
    ['method', 'endpoint']
)

# Gauge for currently active requests
IN_PROGRESS_REQUESTS = Gauge(
    'http_requests_in_progress',
    'Number of HTTP requests currently in progress.',
    ['method', 'endpoint']
)

# Business Metric: Counter for processed items
PROCESSED_ITEMS_TOTAL = Counter(
    'app_processed_items_total',
    'Total number of items processed by the application.',
    ['item_type']
)

# Business Metric: Gauge for current stock level
STOCK_LEVEL = Gauge(
    'app_stock_level',
    'Current stock level for a specific product.',
    ['product_id']
)

# Business Metric: Histogram for processing time of a specific task
TASK_PROCESSING_TIME_SECONDS = Histogram(
    'app_task_processing_time_seconds',
    'Processing time for a specific application task.',
    ['task_name']
)

# Initialize some stock levels
STOCK_LEVEL.labels(product_id='product_A').set(100)
STOCK_LEVEL.labels(product_id='product_B').set(50)

# ----------------------------------------------------------------------------------------------------------------------
# Flask Routes
# ----------------------------------------------------------------------------------------------------------------------

@app.before_request
def before_request_hook():
    """Increments the in-progress requests gauge before each request."""
    request.start_time = time.time()
    IN_PROGRESS_REQUESTS.labels(method=request.method, endpoint=request.path).inc()

@app.after_request
def after_request_hook(response):
    """
    Decrements the in-progress requests gauge, records request duration,
    and increments total requests counter after each request.
    """
    request_duration = time.time() - request.start_time
    IN_PROGRESS_REQUESTS.labels(method=request.method, endpoint=request.path).dec()
    REQUEST_DURATION_SECONDS.labels(method=request.method, endpoint=request.path).observe(request_duration)
    REQUESTS_TOTAL.labels(method=request.method, endpoint=request.path, status_code=response.status_code).inc()
    return response

@app.route('/')
def home():
    """A simple home endpoint."""
    time.sleep(random.uniform(0.01, 0.05)) # Simulate some work
    return "Welcome to the Flask Prometheus App!"

@app.route('/process/<item_type>')
def process_item(item_type):
    """
    An endpoint that simulates processing an item and updates a business counter.
    Also simulates a task with a histogram.
    """
    task_start_time = time.time()
    time.sleep(random.uniform(0.05, 0.2)) # Simulate processing time
    PROCESSED_ITEMS_TOTAL.labels(item_type=item_type).inc()
    TASK_PROCESSING_TIME_SECONDS.labels(task_name='item_processing').observe(time.time() - task_start_time)

    # Simulate stock level change
    if item_type == 'widget' and random.random() < 0.7: # 70% chance to consume stock
        current_stock = STOCK_LEVEL.labels(product_id='product_A').get()
        if current_stock > 0:
            STOCK_LEVEL.labels(product_id='product_A').set(current_stock - 1)
        else:
            print("Stock for product_A is empty!")

    return f"Processed {item_type} successfully!"

@app.route('/update_stock/<product_id>/<int:quantity>')
def update_stock(product_id, quantity):
    """
    An endpoint to manually update stock levels, demonstrating a gauge.
    """
    STOCK_LEVEL.labels(product_id=product_id).set(quantity)
    return f"Stock for {product_id} updated to {quantity}"

@app.route('/error')
def simulate_error():
    """Simulates an internal server error."""
    time.sleep(random.uniform(0.01, 0.03))
    # This will trigger an error, and the after_request hook will capture status_code 500
    raise Exception("Simulated internal server error!")

@app.route('/metrics')
def metrics():
    """
    Exposes Prometheus metrics.
    """
    return Response(generate_latest(), mimetype='text/plain')

# ----------------------------------------------------------------------------------------------------------------------
# Error Handling (to ensure after_request still runs for 500s)
# ----------------------------------------------------------------------------------------------------------------------
@app.errorhandler(Exception)
def handle_exception(e):
    """
    Custom error handler to ensure after_request is called even for unhandled exceptions,
    allowing metrics to be recorded for 500 errors.
    """
    # Log the error if needed
    app.logger.error(f"An error occurred: {e}", exc_info=True)
    # Flask's default error handling will set the status code to 500
    # The after_request hook will then capture this 500 status code.
    return "Internal Server Error", 500

